{
	"html": {
		"value": "<!-- Google Fonts & Font Awesome -->
<p><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&amp;display=swap" rel="stylesheet"></p>
<p> </p>
<p><link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0-beta3/css/all.min.css" rel="stylesheet"></p>
<style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: 'Inter', sans-serif; background-color: #F8FAFC; color: #0F172A; line-height: 1.5; }
        .portal-container { max-width: 1280px; margin: 0 auto; padding: 20px; }

         /* Carousel / Featured Tips */
        .carousel-section { background: #F1F5F9; border-radius: 32px; padding: 2rem; margin-bottom: 50px; text-align: center; }
        .carousel-content { background: white; border-radius: 28px; padding: 2rem; max-width: 700px; margin: 1rem auto; box-shadow: 0 8px 20px rgba(0,0,0,0.05); }
        .carousel-content i { font-size: 2rem; color: #E60000; margin-bottom: 1rem; }
        .carousel-content p { font-size: 1rem; color: #334155; margin-bottom: 1rem; }
        .carousel-dots { display: flex; justify-content: center; gap: 10px; margin-top: 1rem; }
        .dot { width: 10px; height: 10px; background: #CBD5E1; border-radius: 50%; cursor: pointer; }
        .dot.active { background: #E60000; width: 24px; border-radius: 10px; }
 </style>
<!-- ========== CAROUSEL / FEATURED TIPS (OOB: Carousel Widget) ========== -->
<div class="carousel-section">
<div class="carousel-content">
<p><strong>"Staying hydrated boosts your energy and mental clarity. Drink at least 8 glasses of water daily!"</strong></p>
</div>
<div class="carousel-dots">&nbsp;</div>
</div>",
